47	let tmpDir: string;
48	
49	beforeEach(() => {
50	  tmpDir = fs.mkdtempSync(path.join(os.tmpdir(), 'yoke-schema-test-'));
51	});
52	
53	afterEach(() => {
54	  fs.rmSync(tmpDir, { recursive: true, force: true });
