57	function makeDb(): Database.Database {
58	  const dbPath = path.join(tmpDir, `${Math.random().toString(36).slice(2)}.db`);
59	  const db = new Database(dbPath);
60	  db.pragma('busy_timeout = 5000');
61	  db.pragma('journal_mode = WAL');
62	  db.pragma('synchronous = NORMAL');
63	  db.pragma('foreign_keys = ON');
64	  db.exec(
65	    'CREATE TABLE IF NOT EXISTS schema_migrations (version INTEGER PRIMARY KEY, applied_at TEXT NOT NULL)',
66	  );
67	  applyMigrations(db, migrationsDir);
68	  return db;
69	}
70	
71	function tableInfo(db: Database.Database, table: string): ColumnInfo[] {
72	  return db.prepare(`PRAGMA table_info(${table})`).all() as ColumnInfo[];
73	}
74	
75	function colNames(db: Database.Database, table: string): string[] {
76	  return tableInfo(db, table).map((c) => c.name);
77	}
78	
79	function colTypes(db: Database.Database, table: string): Record<string, string> {
80	  const out: Record<string, string> = {};
81	  for (const c of tableInfo(db, table)) out[c.name] = c.type;
82	  return out;
83	}
