387	
388	    // Insert one open and one acknowledged row
389	    db.prepare(
390	      `INSERT INTO pending_attention (workflow_id, kind, payload, created_at)
391	       VALUES ('wf-eqp', 'blocked_item', '{}', '2026-01-01T00:00:00Z')`,
