5	/**
6	 * Applies forward-only numbered SQL migration files from migrationsDir to the
7	 * writer connection.
8	 *
9	 * Conventions:
10	 *   - File names must match /^\d{4}_.*\.sql$/ (e.g. 0001_core_tables.sql).
11	 *   - Files are applied in lexicographic (version-number) order.
12	 *   - Already-applied versions (present in schema_migrations) are skipped.
13	 *   - Each migration is wrapped in a transaction; the version is recorded in
14	 *     schema_migrations on success. If the SQL fails the transaction rolls back
15	 *     and the error propagates to the caller.
16	 *
17	 * schema_migrations must already exist when this is called — bootstrapped by
18	 * openDbPool before migrations run.
19	 *
20	 * @throws {Error} if migrationsDir cannot be read, a SQL file cannot be read,
21	 *                 or a migration SQL statement fails.
22	 */
23	export function applyMigrations(
24	  writer: Database.Database,
25	  migrationsDir: string,
26	): void {
27	  const files = fs
28	    .readdirSync(migrationsDir)
29	    .filter((f) => /^\d{4}_.*\.sql$/.test(f))
30	    .sort();
31	
32	  const checkApplied = writer.prepare<[number]>(
